// // This module implements a 1-bit D-flip-flop with an active-low reset.
module d_flip_flop (
    input wire clk,
    input wire reset,
    input wire D,
    output reg Q
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        Q <= 0;
    end else begin
        Q <= D;
    end
end

endmodule
